// Filtra leads con status 'nuevo' que llevan más de 48h sin gestionar
const ahora = new Date();
const LIMITE_HORAS = 48;

const leadsFiltrados = $input.all().filter(item => {
  const lead = item.json;
  const creado = new Date(lead.created_at);
  const horasTranscurridas = (ahora - creado) / (1000 * 3600);
  return lead.status === 'nuevo' && horasTranscurridas > LIMITE_HORAS;
});

if (leadsFiltrados.length === 0) {
  return [{ json: { total: 0, leads: [] } }];
}

return [{
  json: {
    total: leadsFiltrados.length,
    leads: leadsFiltrados.map(item => item.json)
  }
}];

// Construye el mensaje de alerta
const data = $input.first().json;
const fecha = new Date().toLocaleDateString('es-ES', { 
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' 
});

let mensaje = `ALERTA iAhorro — ${fecha}\n`;
mensaje += `Hay ${data.total} lead(s) con status NUEVO sin gestionar hace más de 48 horas:\n\n`;

data.leads.forEach(lead => {
  const horasEspera = Math.floor((new Date() - new Date(lead.created_at)) / (1000 * 3600));
  mensaje += `- ${lead.lead_id} | Creado: ${new Date(lead.created_at).toLocaleString('es-ES')} | Fuente: ${lead.source} | Importe: ${lead.requested_amount.toLocaleString('es-ES')}€ | Espera: ${horasEspera}h\n`;
});

mensaje += `\nAccion requerida: asignar agente y realizar primer contacto.`;

return [{ json: { mensaje, total: data.total, timestamp: new Date().toISOString() } }];

